<template>
  <div>
    <div class="bb">
      <h2>{{ item.title }}</h2>
      <div>
        <span>作者: 赵日天</span>
        <span>分类: {{ item.tags }}</span>
        <span>发布于: {{ new Date(item.utime * 1000).toLocaleDateString() }}</span>
        <span>浏览({{ item.views }})</span>
        <span>评论: ({{ number }})</span>
      </div>
      <hr />
      <div v-html="item.content"></div>
    </div>
    <comment @countComments="countComments"/>
  </div>
</template>

<script>
import comment from "../components/comment/index";
import axios from "axios";
export default {
  components: {
    comment
  },
  watch: {
    $route(to,from){
      // console.log(to.query)
      this.id = to.query.id;
      axios
      .get("/api/article/details", {
        params: {
          id: this.id
        }
      })
      .then(res => {
        this.item = res.data.data[0];
      });
    }
  },
  created() {
    var id = this.$route.query.id;
    axios
      .get("/api/article/details", {
        params: {
          id: id
        }
      })
      .then(res => {
        this.item = res.data.data[0];
      });
  },
  data() {
    return {
      item: "",
      number: '',
      id: ''
    };
  },
  methods: {
    countComments(num){
      this.number = num
    }
  }
};
</script>

