<template>
  <div class="container">
    <div class="display" v-for="item in comments" :key="item.id">
      <div>
        <span class="name">{{ item.username }}</span>
        <span class="time">{{ new Date(item.ctime*1000).toLocaleDateString()}}</span>
        <!-- <span class="time">{{ item.id}} 楼</span> -->
      </div>
      <div class="content">{{ item.comments }}</div>
      <a class="btn1" @click="changeId(item.id,item.username)" href="#publish">回复</a>
      <div class="reply" v-for="i in item.reply" :key="i.id">
        <div class="info">
          <span class="replyName">{{ i.username}}</span>
          <span>回复</span>
          <span class="replyName">{{ i.parent_username }}</span>
          <span class="time">{{ new Date(i.ctime * 1000).toLocaleDateString() }}</span>
          <a href="#publish" class="btn2" @click="changeId(item.id,i.username)">回复</a>
        </div>
        <div class="word">{{ i.comments }}</div>
        <hr />
      </div>
    </div>
    <div class="publish" id="publish">
      <h3>发表评论</h3>
      <el-input placeholder="昵称" v-model="form.username"></el-input>
      <el-input placeholder="邮箱 (评论被回复时你能收到通知)" v-model="form.email" class="one"></el-input>
      <el-input type="textarea" :rows="3" placeholder="请输入内容" v-model="form.comments"></el-input>

      <div class="btn">
        <el-button @click="submit">提交</el-button>
        <el-button>重写</el-button>
      </div>
    </div>
  </div>
</template>

<script>
import axios from "axios";

export default {
  created() {
    this.form.articleId = this.$route.query.id;
    axios
      .get("/api/comment/get", {
        params: {
          articleId: this.form.articleId
        }
      })
      .then(res => {
        this.comments = res.data.comments;
        console.log(this.comments);
        this.$emit("countComments", this.comments.length);
      });
  },
  data() {
    return {
      form: {
        articleId: "",
        parent: "-1",
        parent_username: "",
        username: "",
        email: "",
        comments: ""
      },
      parentId: "",
      parentName: "",
      comments: "",
  
    };
  },
  methods: {
    submit() {
      if (this.parentId) {
        this.form.parent = this.parentId;
        this.form.parent_username = this.parentName;
      }
      var flag = this.form.username && this.form.email && this.form.comments;
      if (flag) {
        axios
          .post("/api/comment/add", {
            ...this.form
          })
          .then(res => {
            console.log(res);
            location.reload();
          });
      } else {
        alert("请输入完整信息");
      }
    },
    changeId(id, name) {
      this.parentId = id;
      this.parentName = name;
      console.log(this.parentId);
      console.log(name);
    }
  }
};
</script>



